INSERT INTO `jcourse_api_reviewrevision` VALUES (1,4,'听说黄昊老师打分很高，本专业很多人都选','2025-08-08 13:00:59.113000',NULL,2065,1964,3,1),(2,4,'听说黄昊老师打分很高，本专业很多人都','2025-08-08 13:01:05.230000',NULL,2065,1964,3,1),(3,5,'课程内容：学习基本语法知识（各种词性，从句，时态等）\n\n上课自由度：很轻松，几乎不点名（上学期只有五一前点过一次，不过不影响成绩）\n\n考核标准：平时无作业，期末成绩就是期中作文+期末作文的成绩（都是课下写，就是不要全AI）\n\n授课质量：老师人很幽默，讲的都是干活，想认真学也是可以学到一些东西的（需要每节课认真记笔记）','2025-09-04 08:48:16.114000','4.0+',2605,1986,2,19),(4,3,'课程内容：主要在讲题练题\n\n上课自由度：好\n\n考核标准：严格按照学校统一的各板块占比来打平时分\n\n授课质量：讲得挺好的','2025-09-05 07:44:35.506000',NULL,1582,2835,2,29);
